questions = [
  {"id":"3741","tipo":"multipla","disciplina":"Matemática","tema":"Conjuntos","subtema":"Operações com Conjuntos","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Dados A = {1, 2, 3, 4} e B = {3, 4, 5, 6}, qual é A ∩ B (interseção)?","alternativa_a":"{3, 4}","alternativa_b":"{1, 2, 5, 6}","alternativa_c":"{1, 2, 3, 4, 5, 6}","alternativa_d":"{}","alternativa_e":"{1, 2, 3}","resposta_correta":"a","explicacao":"A interseção A ∩ B contém os elementos que pertencem simultaneamente a A e B. A ∩ B = {3, 4}.","resposta":""},
  {"id":"3742","tipo":"multipla","disciplina":"Física","tema":"Mecânica","subtema":"Torque","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Uma força de 10 N é aplicada perpendicularmente a uma alavanca a 0,5 m do pivô. O torque resultante é:","alternativa_a":"5 N·m","alternosta_b":"50 N·m","alternativa_c":"0,5 N·m","alternativa_d":"20 N·m","alternativa_e":"2 N·m","resposta_correta":"a","explicacao":"Torque τ = F × d × sen θ. Como a força é perpendicular (θ = 90°, sen 90° = 1): τ = 10 × 0,5 = 5 N·m.","resposta":""},
  {"id":"3743","tipo":"multipla","disciplina":"Química","tema":"Substâncias","subtema":"Misturas","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O ar atmosférico é um exemplo de:","alternativa_a":"Mistura homogênea (solução gasosa)","alternativa_b":"Substância pura simples","alternativa_c":"Substância pura composta","alternativa_d":"Mistura heterogênea","alternativa_e":"Coloide","resposta_correta":"a","explicacao":"O ar é uma mistura de gases (N₂ ≈78%, O₂ ≈21%, Ar, CO₂, etc.) que se apresenta uniforme em toda a sua extensão, portanto é uma mistura homogênea (solução gasosa).","resposta":""},
  {"id":"3744","tipo":"multipla","disciplina":"Biologia","tema":"Zoologia","subtema":"Equinodermos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"As estrelas-do-mar e os ouriços-do-mar pertencem ao filo Echinodermata. Qual é a característica exclusiva desse filo?","alternativa_a":"Sistema ambulacral (hidrovascular) e endoesqueleto calcário","alternativa_b":"Corpo mole e presença de manto","alternativa_c":"Exoesqueleto quitinoso","alternativa_d":"Notocorda na fase adulta","alternativa_e":"Simetria bilateral permanente","resposta_correta":"a","explicacao":"Equinodermos possuem sistema ambulacral (rede de canais com água que aciona os pés ambulacrais para locomoção e alimentação) e endoesqueleto calcário com espinhos (equino = espinho). Adultos com simetria pentarradial.","resposta":""},
  {"id":"3745","tipo":"multipla","disciplina":"História","tema":"Antiguidade","subtema":"Grécia Antiga","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A democracia ateniense do século V a.C. era limitada porque:","alternativa_a":"Excluía mulheres, escravos e estrangeiros (metecos) da participação política","alternativa_b":"Era uma ditadura disfarçada de democracia","alternativa_c":"Só o rei podia votar nas assembleias","alternativa_d":"Era idêntica à democracia representativa moderna","alternativa_e":"Impedia a liberdade de expressão filosófica","resposta_correta":"a","explicacao":"A democracia de Atenas (Péricles) era direta — cidadãos votavam pessoalmente na Eclésia. Porém, 'cidadão' excluía: mulheres, escravos (grande parte da população) e metecos (estrangeiros residentes). Apenas homens livres atenienses adultos participavam.","resposta":""},
  {"id":"3746","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"Petróleo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A OPEP (Organização dos Países Exportadores de Petróleo) foi fundada para:","alternativa_a":"Coordenar as políticas petrolíferas e controlar os preços do petróleo","alternativa_b":"Desenvolver energias renováveis nos países membros","alternativa_c":"Financiar guerras no Oriente Médio","alternativa_d":"Regular o comércio mundial de commodities","alternativa_e":"Substituir a ONU nas negociações energéticas","resposta_correta":"a","explicacao":"A OPEP foi fundada em 1960 (Bagdá) por Arábia Saudita, Irã, Iraque, Kuwait e Venezuela. Seu objetivo é coordenar as políticas de produção e preço do petróleo, aumentando o poder de barganha dos países produtores frente às multinacionais do setor.","resposta":""},
  {"id":"3747","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Gramática","subtema":"Denotação e Conotação","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Em 'Ele tem um coração de ouro', a palavra 'ouro' está empregada em sentido:","alternativa_a":"Conotativo (figurado — pessoa bondosa)","alternativa_b":"Denotativo (literal — metal precioso)","alternativa_c":"Técnico","alternativa_d":"Arcaico","alternativa_e":"Formal","resposta_correta":"a","explicacao":"Denotação: sentido literal do dicionário. Conotação: sentido figurado, carregado de valores subjetivos. 'Coração de ouro' é conotativo — compara a bondade da pessoa à preciosidade do ouro.","resposta":""},
  {"id":"3748","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Política","subtema":"Arendt","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Hannah Arendt, em 'Origens do Totalitarismo', identificou as raízes do nazismo e do stalinismo em:","alternativa_a":"Antissemitismo, imperialismo e o colapso do Estado-nação","alternativa_b":"Apenas no carisma pessoal dos ditadores","alternativa_c":"Crises econômicas exclusivamente","alternativa_d":"Disputas religiosas medievais","alternativa_e":"Rivalidade entre potências coloniais","resposta_correta":"a","explicacao":"Para Arendt, o totalitarismo (nazismo e stalinismo) foi um fenômeno novo na história, com origens em três elementos: (1) antissemitismo moderno; (2) imperialismo europeu do séc. XIX (que desumanizou populações colonizadas); (3) colapso do Estado-nação e crise das instituições liberais após a 1ª Guerra Mundial.","resposta":""},
  {"id":"3749","tipo":"multipla","disciplina":"Sociologia","tema":"Família","subtema":"Transformações na Família","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"As transformações na estrutura familiar brasileira nas últimas décadas incluem:","alternativa_a":"Redução das famílias nucleares tradicionais e aumento de famílias monoparentais, homoafetivas e recompostas","alternativa_b":"Retorno ao modelo de família extensa pré-industrial","alternativa_c":"Aumento constante do número médio de filhos","alternativa_d":"Eliminação do divórcio como prática social","alternativa_e":"Volta da família patriarcal como modelo dominante","resposta_correta":"a","explicacao":"A família brasileira contemporânea é marcada por: queda da taxa de natalidade, aumento do número de divórcios, crescimento de famílias chefiadas por mulheres (monoparentais), reconhecimento das famílias homoafetivas (STF, 2011) e das famílias recompostas (uniões de casais com filhos de relacionamentos anteriores).","resposta":""},
  {"id":"3750","tipo":"multipla","disciplina":"Matemática","tema":"Progressões","subtema":"PA — Soma dos Termos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A soma dos 10 primeiros termos naturais (1+2+3+...+10) é:","alternativa_a":"55","alternativa_b":"50","alternativa_c":"45","alternativa_d":"100","alternativa_e":"110","resposta_correta":"a","explicacao":"Soma de PA: Sₙ = n(a₁ + aₙ)/2 = 10(1+10)/2 = 10×11/2 = 55. Fórmula de Gauss.","resposta":""},
  {"id":"3751","tipo":"multipla","disciplina":"Física","tema":"Eletricidade","subtema":"Resistores em Série","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Dois resistores de 4 Ω e 6 Ω estão em série. A resistência equivalente é:","alternativa_a":"10 Ω","alternativa_b":"2,4 Ω","alternativa_c":"24 Ω","alternativa_d":"5 Ω","alternativa_e":"1 Ω","resposta_correta":"a","explicacao":"Em série: Req = R₁ + R₂ = 4 + 6 = 10 Ω. Em paralelo seria: 1/Req = 1/4 + 1/6 = 5/12 → Req = 2,4 Ω.","resposta":""},
  {"id":"3752","tipo":"multipla","disciplina":"Química","tema":"Reações Orgânicas","subtema":"Fermentação","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A fermentação alcoólica converte glicose em etanol e CO₂ pela ação de:","alternativa_a":"Leveduras (fungos unicelulares como Saccharomyces cerevisiae)","alternativa_b":"Bactérias aeróbicas","alternativa_c":"Enzimas vegetais","alternativa_d":"Raios ultravioleta","alternativa_e":"Catalisadores inorgânicos","resposta_correta":"a","explicacao":"C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂. Fermentação alcoólica realizada por leveduras (Saccharomyces cerevisiae) em ausência de O₂. Usada na produção de pão, cerveja, vinho e etanol combustível (cana-de-açúcar no Brasil).","resposta":""},
  {"id":"3753","tipo":"multipla","disciplina":"Biologia","tema":"Citologia","subtema":"Retículo Endoplasmático","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O retículo endoplasmático rugoso (RER) difere do liso porque:","alternativa_a":"Possui ribossomos aderidos à membrana, sendo especializado na síntese de proteínas","alternativa_b":"É responsável pela síntese de lipídios","alternativa_c":"Não possui membrana","alternativa_d":"Está presente apenas em células vegetais","alternativa_e":"É exclusivo do núcleo celular","resposta_correta":"a","explicacao":"RER (rugoso): tem ribossomos na superfície → síntese de proteínas destinadas à exportação ou às membranas. REL (liso): sem ribossomos → síntese de lipídios, metabolismo de carboidratos, detoxificação (células hepáticas).","resposta":""},
  {"id":"3754","tipo":"multipla","disciplina":"História","tema":"Brasil Contemporâneo","subtema":"Impeachment","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O impeachment da presidenta Dilma Rousseff (2016) foi fundamentado em:","alternativa_a":"Pedaladas fiscais (manipulação de contas públicas — crime de responsabilidade fiscal)","alternativa_b":"Envolvimento direto na Operação Lava Jato","alternativa_c":"Violação dos direitos humanos","alternativa_d":"Romper relações diplomáticas com os EUA","alternativa_e":"Privatização de estatais sem autorização do Congresso","resposta_correta":"a","explicacao":"O impeachment de Dilma Rousseff foi aprovado em agosto de 2016 com base nas 'pedaladas fiscais' — atraso nos repasses a bancos públicos (BB, CEF) que haviam antecipado recursos para programas sociais, caracterizando crime de responsabilidade fiscal (Lei 1.079/50).","resposta":""},
  {"id":"3755","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Gramática","subtema":"Aspectos do Verbo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Na frase 'Ele estava estudando quando tocou o telefone', os verbos indicam:","alternativa_a":"Ação em progresso (estava estudando) interrompida por ação pontual (tocou)","alternativa_b":"Duas ações simultâneas e concluídas","alternativa_c":"Ações futuras","alternativa_d":"Ação habitual no passado","alternativa_e":"Condição hipotética","resposta_correta":"a","explicacao":"'Estava estudando' (pretérito imperfeito + gerúndio = aspecto durativo/progressivo): ação em curso no passado. 'Tocou' (pretérito perfeito = aspecto pontual): interrompeu a primeira ação. Estrutura típica de narrativas.","resposta":""},
  {"id":"3756","tipo":"multipla","disciplina":"Filosofia","tema":"Ética","subtema":"Ética do Cuidado","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A ética do cuidado, desenvolvida por Carol Gilligan, critica as éticas tradicionais por:","alternativa_a":"Privilegiarem princípios abstratos e universais, negligenciando relações concretas e a vulnerabilidade humana","alternativa_b":"Serem excessivamente emotivas","alternativa_c":"Focarem somente no prazer individual","alternativa_d":"Ignorarem completamente os direitos","alternativa_e":"Defenderem o relativismo moral absoluto","resposta_correta":"a","explicacao":"Carol Gilligan ('In a Different Voice', 1982) contrapôs-se a Kohlberg, argumentando que as éticas dominantes (Kant, Rawls) baseadas em princípios abstratos e justiça imparcial negligenciam a dimensão das relações, do cuidado e da responsabilidade com o outro concreto — dimensão ligada às experiências femininas.","resposta":""},
  {"id":"3757","tipo":"multipla","disciplina":"Matemática","tema":"Álgebra","subtema":"Produtos Notáveis","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O produto (x + 3)² é igual a:","alternativa_a":"x² + 6x + 9","alternativa_b":"x² + 9","alternativa_c":"x² + 3x + 9","alternativa_d":"x² − 6x + 9","alternativa_e":"2x + 6","resposta_correta":"a","explicacao":"(a + b)² = a² + 2ab + b². (x + 3)² = x² + 2(x)(3) + 3² = x² + 6x + 9.","resposta":""},
  {"id":"3758","tipo":"multipla","disciplina":"Química","tema":"Funções Inorgânicas","subtema":"Sais","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O cloreto de sódio (NaCl) é um sal formado por:","alternativa_a":"Ácido clorídrico (HCl) + hidróxido de sódio (NaOH)","alternativa_b":"Ácido sulfúrico + hidróxido de sódio","alternativa_c":"Ácido nítrico + hidróxido de cálcio","alternativa_d":"Ácido acético + amônia","alternativa_e":"Ácido fosfórico + hidróxido de potássio","resposta_correta":"a","explicacao":"Neutralização: HCl + NaOH → NaCl + H₂O. O cloreto de sódio é o sal de cozinha, formado pela neutralização entre o ácido clorídrico (forte) e o hidróxido de sódio (soda cáustica, base forte).","resposta":""},
  {"id":"3759","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Pirâmides Ecológicas","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Em uma pirâmide de energia, a quantidade de energia disponível ao longo da cadeia alimentar:","alternativa_a":"Diminui em cerca de 90% a cada nível trófico","alternativa_b":"Permanece constante em todos os níveis","alternativa_c":"Aumenta nos consumidores","alternativa_d":"Dobra a cada nível trófico","alternativa_e":"É transferida integralmente sem perdas","resposta_correta":"a","explicacao":"Regra dos 10%: apenas cerca de 10% da energia de um nível trófico é transferida ao nível seguinte; os outros 90% são perdidos em calor (metabolismo, respiração). Por isso, cadeias alimentares têm no máximo 4-5 elos.","resposta":""},
  {"id":"3760","tipo":"multipla","disciplina":"Geografia","tema":"Desenvolvimento Humano","subtema":"IDH","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O IDH (Índice de Desenvolvimento Humano) é calculado com base em três dimensões:","alternativa_a":"Saúde (expectativa de vida), educação (anos de escolaridade) e renda (PIB per capita)","alternativa_b":"Renda, poluição e desigualdade","alternativa_c":"Apenas PIB per capita","alternativa_d":"Mortalidade infantil, analfabetismo e desemprego","alternativa_e":"Democracia, liberdade de imprensa e renda","resposta_correta":"a","explicacao":"O IDH foi desenvolvido pelo PNUD (ONU) e combina: (1) saúde — expectativa de vida ao nascer; (2) educação — média de anos de escolaridade e expectativa de anos de estudo; (3) renda — RNB per capita (renda nacional bruta). Varia de 0 a 1.","resposta":""},
  {"id":"4501","tipo":"dissertativa","disciplina":"Matemática","tema":"Geometria Plana","subtema":"Semelhança de Triângulos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Dois triângulos semelhantes têm lados correspondentes de 6 cm e 9 cm. Se a área do menor triângulo é 24 cm², qual é a área do maior?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Razão de semelhança: k = 9/6 = 3/2. A razão das áreas é k² = (3/2)² = 9/4. Área maior = 24 × 9/4 = 216/4 = 54 cm².","resposta":"54 cm²"},
  {"id":"4502","tipo":"dissertativa","disciplina":"Física","tema":"Óptica","subtema":"Refração","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique o fenômeno da refração da luz e como ele explica a aparência 'quebrada' de um lápis na água.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Refração é a mudança de direção e velocidade da luz ao passar de um meio para outro de diferente densidade óptica (índice de refração). A lei de Snell-Descartes: n₁ × sen θ₁ = n₂ × sen θ₂. A água tem índice de refração n ≈ 1,33 (maior que o ar, n=1). Quando a luz passa do ar para a água, desacelera e se desvia. Ao observar um lápis parcialmente submerso, a luz refletida na parte submersa sofre refração ao sair da água, fazendo o lápis parecer quebrado ou deslocado na superfície.","resposta":"Refração: mudança de velocidade e direção da luz ao mudar de meio; lei de Snell; o lápis parece quebrado porque a luz muda de direção ao sair da água"},
  {"id":"4503","tipo":"dissertativa","disciplina":"Química","tema":"Bioquímica","subtema":"Carboidratos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Qual a diferença entre carboidratos simples e complexos? Cite um exemplo de cada e sua função no organismo.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Carboidratos simples (monossacarídeos e dissacarídeos): moléculas pequenas, rapidamente absorvidas. Ex.: glicose (monossacarídeo — combustível direto das células, especialmente neurônios) e sacarose (dissacarídeo — açúcar comum, glicose + frutose). Carboidratos complexos (polissacarídeos): cadeias longas de monossacarídeos, digestão mais lenta. Ex.: amido (reserva vegetal — arroz, batata, pão) e celulose (parede celular vegetal — fibra alimentar não digerida por humanos). Função: principal fonte de energia do organismo (4 kcal/g); glicogênio é a reserva em animais.","resposta":"Simples (glicose, sacarose): absorção rápida, energia imediata. Complexos (amido, celulose): absorção lenta, energia sustentada ou fibra"},
  {"id":"4504","tipo":"dissertativa","disciplina":"Biologia","tema":"Genética","subtema":"Epistasia","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"O que é epistasia na genética e como ela difere da dominância completa?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Dominância completa: interação entre alelos do mesmo gene (loco) — o alelo dominante mascara o recessivo. Ex.: Aa → fenótipo A. Epistasia: interação entre genes diferentes (loci distintos) — um gene interfere na expressão de outro. Ex.: cor do pelo em cobaias — gene C (cor) e gene A (aguti): se o animal for cc, não produz pigmento independente do gene A (epistasia recessiva). Ambas geram desvios nas proporções mendelianas clássicas (9:3:3:1), mas por mecanismos distintos: dominância opera dentro do mesmo gene; epistasia opera entre genes.","resposta":"Epistasia: interação entre genes diferentes (um suprime o outro); dominância: interação entre alelos do mesmo gene — epistasia distorce as proporções 9:3:3:1"},
  {"id":"4505","tipo":"dissertativa","disciplina":"História","tema":"Brasil Colonial","subtema":"Economia Colonial","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique o conceito de 'sentido da colonização' de Caio Prado Júnior aplicado ao Brasil.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Caio Prado Júnior ('Formação do Brasil Contemporâneo', 1942) argumenta que a colonização brasileira foi orientada pelo 'sentido da colonização': produzir para o mercado externo europeu (Portugal/metrópole), não para atender às necessidades da população local. O Brasil foi estruturado como economia de exportação de produtos tropicais (pau-brasil, açúcar, ouro, algodão) usando mão de obra escravizada. Essa estrutura colonial — latifúndio, monocultura, escravidão, exportação — moldou as desigualdades socioeconômicas que persistem no Brasil até hoje.","resposta":"'Sentido da colonização': o Brasil foi estruturado para produzir ao mercado externo (latifúndio, monocultura, escravidão) — explicação histórica das desigualdades brasileiras"},
  {"id":"4506","tipo":"dissertativa","disciplina":"Língua Portuguesa","tema":"Literatura","subtema":"Regionalismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Caracterize o Regionalismo literário brasileiro, citando um autor e uma obra representativa.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"O Regionalismo é uma tendência literária que valoriza as especificidades de determinadas regiões do Brasil — paisagem, linguagem, costumes, tipos humanos. No Modernismo brasileiro (2ª geração, 1930-45), o Regionalismo nordestino foi dominante: João Cabral de Melo Neto ('Morte e Vida Severina'), Rachel de Queiroz ('O Quinze'), Jorge Amado (Bahia — 'Capitães da Areia'). Graciliano Ramos ('Vidas Secas') é o nome mais canônico: linguagem seca e enxuta espelha a aridez do Sertão e a miséria do sertanejo. O Regionalismo de 30 tem forte denúncia social.","resposta":"Regionalismo de 30: valoriza culturas regionais com denúncia social; Graciliano Ramos — 'Vidas Secas' (sertão nordestino, linguagem enxuta)"},
  {"id":"4507","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia da Religião","subtema":"Provas da Existência de Deus","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Apresente o argumento ontológico de Anselmo de Cantuária para a existência de Deus e a crítica de Kant a ele.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Argumento ontológico (Anselmo, séc. XI): Deus é 'aquele do qual nada maior pode ser pensado' (id quo nihil maius cogitari possit). Se Deus existisse apenas no pensamento mas não na realidade, poderíamos conceber algo maior (o mesmo ser existindo também na realidade) — contradição. Logo, Deus deve existir na realidade. Crítica de Kant ('Crítica da Razão Pura'): existência não é um predicado real — dizer que algo existe não acrescenta nenhuma propriedade ao conceito de uma coisa. 100 táleres reais e 100 táleres imaginários têm o mesmo conceito; a diferença está na existência, não no conteúdo conceitual. Portanto, o argumento ontológico é inválido.","resposta":"Anselmo: Deus existe porque o conceito perfeito implica existência real. Kant critica: existência não é predicado — não se pode deduzir a existência real de um conceito"},
  {"id":"4508","tipo":"dissertativa","disciplina":"Sociologia","tema":"Terceiro Setor","subtema":"ONGs e Sociedade Civil","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é o Terceiro Setor e qual é seu papel na sociedade contemporânea?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"O Terceiro Setor é o conjunto de organizações sem fins lucrativos e não governamentais que atuam para o bem público — ONGs, associações, fundações, institutos. Primeiro setor: Estado (governo). Segundo setor: mercado (empresas). Terceiro setor: sociedade civil organizada. Papel: preencher lacunas do Estado na provisão de serviços sociais (saúde, educação, assistência); promover cidadania e direitos humanos; fiscalizar o poder público; articular demandas de grupos vulneráveis. Críticas: risco de 'terceirização' das obrigações do Estado, dependência de financiamento externo e falta de controle democrático.","resposta":"Terceiro Setor: ONGs e organizações sem fins lucrativos que complementam o Estado na provisão de serviços sociais e defesa de direitos"},
  {"id":"4509","tipo":"dissertativa","disciplina":"Geografia","tema":"Geopolítica","subtema":"China","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Por que a China se tornou uma das principais potências econômicas do século XXI?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"A ascensão econômica chinesa deve-se a múltiplos fatores: (1) Reformas de Deng Xiaoping (1978): abertura econômica com 'socialismo de mercado', zonas econômicas especiais e atração de investimentos estrangeiros; (2) Mão de obra abundante e barata → fábrica do mundo; (3) Enorme mercado consumidor interno (1,4 bilhão de habitantes); (4) Alta taxa de investimento em infraestrutura e educação; (5) Exportação massiva de manufaturados; (6) Políticas industriais estratégicas (Made in China 2025). A China tornou-se a 2ª maior economia do mundo (PIB), maior exportadora e maior emissora de CO₂.","resposta":"Reformas de Deng Xiaoping (1978), mão de obra barata, mercado interno gigante e políticas industriais estratégicas impulsionaram a China a 2ª maior economia mundial"},
  {"id":"4510","tipo":"dissertativa","disciplina":"Matemática","tema":"Funções","subtema":"Função Modular","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Resolva a equação |2x − 4| = 6 e interprete geometricamente.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"|2x − 4| = 6 → dois casos: Caso 1: 2x − 4 = 6 → 2x = 10 → x = 5. Caso 2: 2x − 4 = −6 → 2x = −2 → x = −1. Interpretação geométrica: |2x − 4| = 2|x − 2| = 6 → |x − 2| = 3. Isso significa a distância de x ao ponto 2 na reta real é igual a 3. Os pontos a distância 3 de 2 são: 2 + 3 = 5 e 2 − 3 = −1.","resposta":"x = 5 ou x = −1; geometricamente, pontos a distância 3 do ponto 2 na reta real"},
]

